example.code:
const personne = {
  prenom: 'Alice',
  age: 30,
  estDeveloppeur: true
};

// Accès aux propriétés
console.log(personne.prenom); // 'Alice'
console.log(personne['age']); // 30 (notation crochet)

// Modifier une propriété
personne.age = 31;

// Ajouter une propriété
personne.ville = 'Paris';

// Destructuring : extraire plusieurs propriétés en une ligne
const { prenom, age } = personne;
console.log(prenom, age); // 'Alice' 31
